// ─── SLIDE 2: DIAGNOSIS ──────────────────────────────────────────
async function slide2(pptx, data) {
  const s = pptx.addSlide();

  // White background
  s.addShape("rect", {
    x: 0, y: 0, w: W, h: H,
    fill: { color: C.white },
    line: { color: C.white, width: 0 },
  });

  // Top bar
  s.addShape("rect", {
    x: 0, y: 0, w: W, h: 0.7,
    fill: { color: C.black },
    line: { color: C.black, width: 0 },
  });
  s.addShape("rect", {
    x: 0, y: 0.68, w: W, h: 0.04,
    fill: { color: C.red },
    line: { color: C.red, width: 0 },
  });

  // Logo on dark bar
  s.addImage({ data: LOGO_LIGHT, x: 0.4, y: 0.08, w: 2.0, h: 0.42 });

  // Section label
  s.addText("WHAT WE FOUND", {
    x: 0.5, y: 0.88, w: 6, h: 0.3,
    fontSize: 8,
    fontFace: "Arial",
    color: C.red,
    bold: true,
    charSpacing: 3,
    margin: 0,
  });

  // Main headline — dynamic sizing
  const headline = data.headline || "Your business is losing customers every day";
  const hlSize = dynamicFontSize(headline, 45, 22, 18, 15);
  s.addText(headline, {
    x: 0.5, y: 1.22, w: 12.3, h: 0.9,
    fontSize: hlSize,
    fontFace: "Arial",
    color: C.black,
    bold: true,
    margin: 0,
  });

  redLine(s, 0.5, 2.08, 2.5);

  // Three problem cards
  const problems = [
    { label: "01", text: data.problem_1 || "" },
    { label: "02", text: data.problem_2 || "" },
    { label: "03", text: data.problem_3 || "" },
  ];

  const cardW = 3.9;
  const cardH = 3.6;
  const cardY = 2.35;
  const gap = 0.27;
  const startX = 0.5;

  problems.forEach((p, i) => {
    const x = startX + i * (cardW + gap);

    // Card background
    s.addShape("roundRect", {
      x, y: cardY, w: cardW, h: cardH,
      fill: { color: C.offWhite },
      line: { color: "E0E0E0", width: 0.8 },
      rectRadius: 0.08,
    });

    // Red left stripe
    s.addShape("rect", {
      x, y: cardY, w: 0.06, h: cardH,
      fill: { color: C.red },
      line: { color: C.red, width: 0 },
    });

    // Number label
    s.addText(p.label, {
      x: x + 0.16, y: cardY + 0.15, w: 0.6, h: 0.4,
      fontSize: 9,
      fontFace: "Arial",
      color: C.red,
      bold: true,
      charSpacing: 1,
      margin: 0,
    });

    // Problem text
    const pSize = dynamicFontSize(p.text, 180, 11, 10, 9);
    s.addText(p.text, {
      x: x + 0.16, y: cardY + 0.58, w: cardW - 0.28, h: cardH - 0.72,
      fontSize: 17,
      fontFace: "Arial",
      color: C.black,
      align: "center",
      valign: "middle",
      margin: 0,
      wrap: true,
    });
  });
}

// ─── SLIDE 3: SOLUTION ───────────────────────────────────────────
async function slide3(pptx, data) {
  const s = pptx.addSlide();

  // Black background
  s.addShape("rect", {
    x: 0, y: 0, w: W, h: H,
    fill: { color: C.black },
    line: { color: C.black, width: 0 },
  });

  // Top bar
  s.addShape("rect", {
    x: 0, y: 0, w: W, h: 0.7,
    fill: { color: "0A0A0A" },
    line: { color: "0A0A0A", width: 0 },
  });
  s.addShape("rect", {
    x: 0, y: 0.68, w: W, h: 0.04,
    fill: { color: C.red },
    line: { color: C.red, width: 0 },
  });

  s.addImage({ data: LOGO_LIGHT, x: 0.4, y: 0.08, w: 2.0, h: 0.42 });

  s.addText("HOW WE SOLVE THIS", {
    x: 0.5, y: 0.88, w: 6, h: 0.3,
    fontSize: 8,
    fontFace: "Arial",
    color: C.red,
    bold: true,
    charSpacing: 3,
    margin: 0,
  });

  s.addText("Three moves. One system. Measurable output.", {
    x: 0.5, y: 1.22, w: 10, h: 0.5,
    fontSize: 20,
    fontFace: "Arial",
    color: C.white,
    bold: true,
    margin: 0,
  });

  redLine(s, 0.5, 1.7, 2.0);

  // Load icons
  const iconNames = [
    data.solution_icon_1 || "FaRocket",
    data.solution_icon_2 || "FaChartLine",
    data.solution_icon_3 || "FaBullseye",
  ];

  let icons = [];
  for (const name of iconNames) {
    try {
      icons.push(await iconBase64(iconLib(name), "#FE0000", 128));
    } catch (e) {
      icons.push(null);
    }
  }

  const solutions = [
    data.solution_1 || "",
    data.solution_2 || "",
    data.solution_3 || "",
  ];

  const cardW = 3.9;
  const cardH = 3.8;
  const cardY = 2.0;
  const gap = 0.27;
  const startX = 0.5;

  solutions.forEach((sol, i) => {
    const x = startX + i * (cardW + gap);

    s.addShape("roundRect", {
      x, y: cardY, w: cardW, h: cardH,
      fill: { color: C.cardDark },
      line: { color: C.border, width: 0.8 },
      rectRadius: 0.08,
    });

    // Icon
    if (icons[i]) {
      s.addImage({ data: icons[i], x: x + 0.2, y: cardY + 0.2, w: 0.5, h: 0.5 });
    }

    // Step number
    s.addText(`0${i + 1}`, {
      x: x + cardW - 0.7, y: cardY + 0.18, w: 0.5, h: 0.35,
      fontSize: 11,
      fontFace: "Arial",
      color: C.red,
      bold: true,
      align: "right",
      margin: 0,
    });

    // Solution text
    const sSize = dynamicFontSize(sol, 140, 13.5, 12, 10.5);
    s.addText(sol, {
      x: x + 0.2, y: cardY + 0.85, w: cardW - 0.4, h: cardH - 1.1,
      fontSize: sSize,
      fontFace: "Arial",
      color: "CCCCCC",
      margin: 0,
      wrap: true,
    });
  });
}

