// ─── GENERATE ENDPOINT ───────────────────────────────────────────
app.post("/generate", async (req, res) => {
  try {
    const data = req.body;

    if (!data || !data.company_name) {
      return res.status(400).json({ error: "Missing company_name in request body" });
    }

    const pptx = new pptxgen();
    pptx.layout = "LAYOUT_WIDE";
    pptx.defineLayout({ name: "LAYOUT_WIDE", width: W, height: H });

    await slide1(pptx, data);
    await slide2(pptx, data);
    await slide3(pptx, data);
    await slide4(pptx, data);
    await slide5(pptx, data);

    const buffer = await pptx.write("nodebuffer");

    res.set({
      "Content-Type": "application/vnd.openxmlformats-officedocument.presentationml.presentation",
      "Content-Disposition": `attachment; filename="${data.company_name.replace(/[^a-z0-9]/gi, "_")}_ProScaleMEDIA.pptx"`,
      "Content-Length": buffer.length,
    });

    res.send(buffer);

  } catch (err) {
    console.error("Generation error:", err);
    res.status(500).json({ error: err.message });
  }
});

